local Players = game:GetService("Players") local RunService = game:GetService("RunService") local UserInputService = game:GetService("UserInputService") local Workspace = game:GetService("Workspace") local player = Players.LocalPlayer local ANIM_ID = "10503381238" local RAGDOLL_ANIM_ID = "10473655645" local END_ANIM_ID = "180436148" local NEARBY_RANGE = 7 local WAIT_BEFORE_ACTION = 0.2775 local TELEPORT_DURATION = 0.6 local VERTICAL_OFFSET = 2.5 local TELEPORT_OFFSET = 0.5 local UPWARD_ANGLE = 50 local FACE_DISTANCE = 1.5 local COOLDOWN_TIME = 5.0 local RANDOM_RADIUS = 1 local uiState = { enabled = false, minimized = false, position = UDim2.new(0, 10, 0, 60), } local isEnabled = false local isExecuting = false local isCooldown = false local cooldownEndTime = 0 local isMinimized = false local cooldownLabel = nil local frame = nil local minimizedFrame = nil local gui = nil local toggleBtn = nil local function randomOffset() local angle = math.random() * math.pi * 2 local dist = math.random() * RANDOM_RADIUS return Vector3.new( math.cos(angle) * dist, 0, math.sin(angle) * dist ) end local function createUI() local existing = player.PlayerGui:FindFirstChild("SupaTechUI") if existing then if frame then frame.Visible = not uiState.minimized if minimizedFrame then minimizedFrame.Visible = uiState.minimized end if toggleBtn then toggleBtn.Text = uiState.enabled and "ON" or "OFF" toggleBtn.BackgroundColor3 = uiState.enabled and Color3.fromRGB(0, 255, 100) or Color3.fromRGB(255, 0, 0) end isEnabled = uiState.enabled isMinimized = uiState.minimized end return end gui = Instance.new("ScreenGui") gui.Name = "SupaTechUI" gui.ResetOnSpawn = false gui.Parent = player:WaitForChild("PlayerGui") local bgColor = Color3.fromRGB(28, 28, 28) local accentColor = Color3.fromRGB(255, 50, 100) frame = Instance.new("Frame") frame.Size = UDim2.new(0, 170, 0, 85) frame.Position = uiState.position frame.BackgroundColor3 = bgColor frame.BackgroundTransparency = 0.05 frame.BorderSizePixel = 0 frame.Active = true frame.Parent = gui local corner = Instance.new("UICorner") corner.CornerRadius = UDim.new(0, 10) corner.Parent = frame local stroke = Instance.new("UIStroke") stroke.Color = accentColor stroke.Thickness = 1.5 stroke.Parent = frame local titleBar = Instance.new("Frame") titleBar.Size = UDim2.new(1, 0, 0, 28) titleBar.BackgroundColor3 = bgColor titleBar.BackgroundTransparency = 0.05 titleBar.BorderSizePixel = 0 titleBar.Active = true titleBar.Parent = frame local titleCorner = Instance.new("UICorner") titleCorner.CornerRadius = UDim.new(0, 10) titleCorner.Parent = titleBar local titleMask = Instance.new("Frame") titleMask.Size = UDim2.new(1, 0, 0, 12) titleMask.Position = UDim2.new(0, 0, 1, -12) titleMask.BackgroundColor3 = bgColor titleMask.BackgroundTransparency = 0.05 titleMask.BorderSizePixel = 0 titleMask.Parent = titleBar local label = Instance.new("TextLabel") label.Size = UDim2.new(0, 120, 1, 0) label.Position = UDim2.new(0, 10, 0, 0) label.BackgroundTransparency = 1 label.Text = "by 混 Supa Tech" label.TextColor3 = Color3.fromRGB(255, 255, 255) label.TextSize = 13 label.Font = Enum.Font.GothamBold label.TextXAlignment = Enum.TextXAlignment.Left label.Parent = titleBar local closeBtn = Instance.new("TextButton") closeBtn.Size = UDim2.new(0, 22, 0, 22) closeBtn.Position = UDim2.new(1, -96, 0, 3) closeBtn.BackgroundColor3 = Color3.fromRGB(180, 40, 40) closeBtn.Text = "✕" closeBtn.TextColor3 = Color3.fromRGB(255, 255, 255) closeBtn.TextSize = 14 closeBtn.Font = Enum.Font.GothamBold closeBtn.Parent = titleBar local closeCorner = Instance.new("UICorner") closeCorner.CornerRadius = UDim.new(0, 5) closeCorner.Parent = closeBtn closeBtn.MouseButton1Click:Connect(function() if gui then gui:Destroy() gui = nil frame = nil minimizedFrame = nil cooldownLabel = nil toggleBtn = nil end isEnabled = false uiState.enabled = false end) toggleBtn = Instance.new("TextButton") toggleBtn.Size = UDim2.new(0, 36, 0, 22) toggleBtn.Position = UDim2.new(1, -70, 0, 3) toggleBtn.BackgroundColor3 = uiState.enabled and Color3.fromRGB(0, 255, 100) or Color3.fromRGB(255, 0, 0) toggleBtn.Text = uiState.enabled and "ON" or "OFF" toggleBtn.TextColor3 = Color3.fromRGB(255, 255, 255) toggleBtn.TextSize = 11 toggleBtn.Font = Enum.Font.GothamBold toggleBtn.Parent = titleBar local toggleCorner = Instance.new("UICorner") toggleCorner.CornerRadius = UDim.new(0, 6) toggleCorner.Parent = toggleBtn toggleBtn.MouseButton1Click:Connect(function() isEnabled = not isEnabled uiState.enabled = isEnabled toggleBtn.Text = isEnabled and "ON" or "OFF" toggleBtn.BackgroundColor3 = isEnabled and Color3.fromRGB(0, 255, 100) or Color3.fromRGB(255, 0, 0) end) local minBtn = Instance.new("TextButton") minBtn.Size = UDim2.new(0, 22, 0, 22) minBtn.Position = UDim2.new(1, -26, 0, 3) minBtn.BackgroundColor3 = Color3.fromRGB(60, 60, 60) minBtn.Text = "−" minBtn.TextColor3 = Color3.fromRGB(255, 255, 255) minBtn.TextSize = 14 minBtn.Font = Enum.Font.GothamBold minBtn.Parent = titleBar local minCorner = Instance.new("UICorner") minCorner.CornerRadius = UDim.new(0, 5) minCorner.Parent = minBtn minBtn.MouseButton1Click:Connect(function() isMinimized = true uiState.minimized = true frame.Visible = false minimizedFrame.Visible = true minimizedFrame.Position = frame.Position end) cooldownLabel = Instance.new("TextLabel") cooldownLabel.Size = UDim2.new(1, 0, 0, 22) cooldownLabel.Position = UDim2.new(0, 0, 0, 32) cooldownLabel.BackgroundTransparency = 1 cooldownLabel.Text = "就绪" cooldownLabel.TextColor3 = Color3.fromRGB(150, 255, 150) cooldownLabel.TextSize = 12 cooldownLabel.Font = Enum.Font.GothamBold cooldownLabel.TextXAlignment = Enum.TextXAlignment.Center cooldownLabel.Parent = frame local statusBar = Instance.new("Frame") statusBar.Size = UDim2.new(1, -20, 0, 4) statusBar.Position = UDim2.new(0, 10, 0, 60) statusBar.BackgroundColor3 = Color3.fromRGB(50, 50, 50) statusBar.BorderSizePixel = 0 statusBar.Parent = frame local statusCorner = Instance.new("UICorner") statusCorner.CornerRadius = UDim.new(0, 2) statusCorner.Parent = statusBar local statusFill = Instance.new("Frame") statusFill.Size = UDim2.new(1, 0, 1, 0) statusFill.BackgroundColor3 = Color3.fromRGB(0, 255, 100) statusFill.BorderSizePixel = 0 statusFill.Parent = statusBar local statusFillCorner = Instance.new("UICorner") statusFillCorner.CornerRadius = UDim.new(0, 2) statusFillCorner.Parent = statusFill local function updateStatusFill() if isCooldown then local remaining = cooldownEndTime - tick() if remaining > 0 then local progress = remaining / COOLDOWN_TIME statusFill.Size = UDim2.new(progress, 0, 1, 0) statusFill.BackgroundColor3 = Color3.fromRGB(255, 200, 50) else statusFill.Size = UDim2.new(1, 0, 1, 0) statusFill.BackgroundColor3 = Color3.fromRGB(0, 255, 100) end else statusFill.Size = UDim2.new(1, 0, 1, 0) statusFill.BackgroundColor3 = Color3.fromRGB(0, 255, 100) end end RunService.Heartbeat:Connect(updateStatusFill) local function makeDraggable(dragTarget, moveTarget) local dragging = false local dragStart, startPos dragTarget.InputBegan:Connect(function(input) if input.UserInputType == Enum.UserInputType.MouseButton1 or input.UserInputType == Enum.UserInputType.Touch then dragging = true dragStart = input.Position startPos = moveTarget.Position input.Changed:Connect(function() if input.UserInputState == Enum.UserInputState.End then dragging = false end end) end end) UserInputService.InputChanged:Connect(function(input) if dragging and (input.UserInputType == Enum.UserInputType.MouseMovement or input.UserInputType == Enum.UserInputType.Touch) then local delta = input.Position - dragStart local newPos = UDim2.new( startPos.X.Scale, startPos.X.Offset + delta.X, startPos.Y.Scale, startPos.Y.Offset + delta.Y ) moveTarget.Position = newPos if moveTarget == frame then uiState.position = newPos end end end) end makeDraggable(titleBar, frame) minimizedFrame = Instance.new("TextButton") minimizedFrame.Size = UDim2.new(0, 50, 0, 50) minimizedFrame.Position = frame.Position minimizedFrame.BackgroundColor3 = bgColor minimizedFrame.BackgroundTransparency = 0.05 minimizedFrame.Text = "混" minimizedFrame.TextColor3 = accentColor minimizedFrame.TextSize = 20 minimizedFrame.Font = Enum.Font.GothamBlack minimizedFrame.Visible = uiState.minimized minimizedFrame.Parent = gui local minFrameCorner = Instance.new("UICorner") minFrameCorner.CornerRadius = UDim.new(0, 12) minFrameCorner.Parent = minimizedFrame local minFrameStroke = Instance.new("UIStroke") minFrameStroke.Color = accentColor minFrameStroke.Thickness = 2 minFrameStroke.Parent = minimizedFrame minimizedFrame.MouseButton1Click:Connect(function() isMinimized = false uiState.minimized = false minimizedFrame.Visible = false frame.Visible = true frame.Position = minimizedFrame.Position uiState.position = frame.Position end) makeDraggable(minimizedFrame, minimizedFrame) isEnabled = uiState.enabled isMinimized = uiState.minimized end createUI() local function isPlayingAnim(hum, animId) if not hum then return false end for _, track in ipairs(hum:GetPlayingAnimationTracks()) do local anim = track.Animation if anim then local id = anim.AnimationId if id and string.find(id, animId) then return true end end end return false end local function getNearestEnemy() local char = player.Character if not char then return nil, nil end local root = char:FindFirstChild("HumanoidRootPart") if not root then return nil, nil end local nearest = nil local nearestRoot = nil local nearestDist = math.huge local myPos = root.Position for _, other in ipairs(Players:GetPlayers()) do if other ~= player then local oChar = other.Character if oChar then local oRoot = oChar:FindFirstChild("HumanoidRootPart") if oRoot then local dist = (myPos - oRoot.Position).Magnitude if dist < nearestDist then nearestDist = dist nearest = oChar nearestRoot = oRoot end end end end end local allModels = Workspace:GetDescendants() for _, obj in ipairs(allModels) do if obj:IsA("Model") and obj ~= char then local hum = obj:FindFirstChild("Humanoid") local oRoot = obj:FindFirstChild("HumanoidRootPart") if hum and oRoot then local dist = (myPos - oRoot.Position).Magnitude if dist < nearestDist then nearestDist = dist nearest = obj nearestRoot = oRoot end end end end if nearest and nearestRoot then return nearest, nearestRoot end return nil, nil end local function doDash() local char = player.Character if not char then return end local comm = char:FindFirstChild("Communicate") if comm then local args = { { Dash = Enum.KeyCode.W, Key = Enum.KeyCode.Q, Goal = "KeyPress", MousePos = CFrame.new(-36.971492767333984, 438.15667724609375, 86.00199127197266, -0.9908232092857361, -0.0044507840648293495, 0.1350911408662796, -4.656612873077393e-10, 0.999457836151123, 0.03292866051197052, -0.13516442477703094, 0.03262647986412048, -0.9902859330177307) } } comm:FireServer(unpack(args)) isCooldown = true cooldownEndTime = tick() + 5.0 end end local function updateCooldown() if isCooldown then local remaining = cooldownEndTime - tick() if remaining <= 0 then isCooldown = false end end if cooldownLabel then if isCooldown then local remaining = cooldownEndTime - tick() if remaining > 0 then cooldownLabel.Text = string.format("冷却: %.1f秒", remaining) cooldownLabel.TextColor3 = Color3.fromRGB(255, 200, 100) else cooldownLabel.Text = "就绪" cooldownLabel.TextColor3 = Color3.fromRGB(150, 255, 150) end else cooldownLabel.Text = "就绪" cooldownLabel.TextColor3 = Color3.fromRGB(150, 255, 150) end end end local function startTeleportLoop(enemyChar, enemyRoot) local startTime = tick() local myChar = player.Character if not myChar then return end local myRoot = myChar:FindFirstChild("HumanoidRootPart") if not myRoot then return end local myHum = myChar:FindFirstChild("Humanoid") if not myHum then return end local enemyHum = enemyChar:FindFirstChild("Humanoid") if not enemyHum then return end myHum.PlatformStand = true local fixedOffset = randomOffset() local myPos = myRoot.Position local enemyPos = enemyRoot.Position local dirToEnemy = (enemyPos - myPos).Unit local facePos = enemyPos - dirToEnemy * FACE_DISTANCE facePos = Vector3.new(facePos.X, enemyPos.Y, facePos.Z) myRoot.CFrame = CFrame.new(facePos + fixedOffset) * CFrame.Angles(math.rad(UPWARD_ANGLE), 0, 0) task.wait(0.1) local footPos = enemyRoot.Position - Vector3.new(0, TELEPORT_OFFSET, 0) myRoot.CFrame = CFrame.new(footPos + fixedOffset) * CFrame.Angles(math.rad(UPWARD_ANGLE), 0, 0) while tick() - startTime < TELEPORT_DURATION do if not isEnabled then break end if not enemyRoot or not enemyRoot.Parent then break end if not myRoot or not myRoot.Parent then break end if not myHum then break end if isPlayingAnim(enemyHum, END_ANIM_ID) or isPlayingAnim(enemyHum, RAGDOLL_ANIM_ID) then break end local newFootPos = enemyRoot.Position - Vector3.new(0, TELEPORT_OFFSET, 0) myRoot.CFrame = CFrame.new(newFootPos + fixedOffset) * CFrame.Angles(math.rad(UPWARD_ANGLE), 0, 0) task.wait() end if enemyRoot and enemyRoot.Parent and myRoot and myRoot.Parent then local finalFootPos = enemyRoot.Position - Vector3.new(0, VERTICAL_OFFSET, 0) myRoot.CFrame = CFrame.new(finalFootPos + fixedOffset) * CFrame.Angles(math.rad(UPWARD_ANGLE), 0, 0) end myHum.PlatformStand = false end local function executeSupaTech() if isExecuting then return end if isCooldown then return end isExecuting = true local enemyChar, enemyRoot = getNearestEnemy() if not enemyChar or not enemyRoot then isExecuting = false return end task.wait(WAIT_BEFORE_ACTION) if not enemyChar.Parent or not enemyRoot.Parent then isExecuting = false return end local enemyHum2 = enemyChar:FindFirstChild("Humanoid") if enemyHum2 and (isPlayingAnim(enemyHum2, RAGDOLL_ANIM_ID) or isPlayingAnim(enemyHum2, END_ANIM_ID)) then isExecuting = false return end doDash() startTeleportLoop(enemyChar, enemyRoot) isExecuting = false end RunService.Heartbeat:Connect(function() if not isEnabled then if isExecuting then isExecuting = false end return end if isExecuting then return end if isCooldown then return end local char = player.Character if not char then return end local hum = char:FindFirstChild("Humanoid") if not hum then return end if isPlayingAnim(hum, ANIM_ID) then local enemyChar, enemyRoot = getNearestEnemy() if enemyChar and enemyRoot then local myRoot = char:FindFirstChild("HumanoidRootPart") if myRoot then local dist = (myRoot.Position - enemyRoot.Position).Magnitude if dist <= NEARBY_RANGE then task.spawn(executeSupaTech) end end end end end) RunService.Heartbeat:Connect(function() updateCooldown() end) player.CharacterAdded:Connect(function() isExecuting = false isCooldown = false cooldownEndTime = 0 if not gui or not gui.Parent then createUI() else if frame then frame.Visible = not uiState.minimized if minimizedFrame then minimizedFrame.Visible = uiState.minimized minimizedFrame.Position = uiState.position end if toggleBtn then toggleBtn.Text = uiState.enabled and "ON" or "OFF" toggleBtn.BackgroundColor3 = uiState.enabled and Color3.fromRGB(0, 255, 100) or Color3.fromRGB(255, 0, 0) end isEnabled = uiState.enabled isMinimized = uiState.minimized end end end)
